node -e "
const fs = require('fs');
const path = require('path');
try {
  const memFile = path.join(process.cwd(), '.claude', 'memory', 'project.json');
  if (fs.existsSync(memFile)) {
    const mem = JSON.parse(fs.readFileSync(memFile, 'utf8'));
    mem.last_session = new Date().toISOString();
    fs.writeFileSync(memFile, JSON.stringify(mem, null, 2));
  }
} catch(e) {}
const logFile = path.join(process.env.HOME, '.claude', 'claudopus-agent-log.jsonl');
const entry = JSON.stringify({
  event: 'Stop',
  ts: new Date().toISOString(),
  session: process.env.CLAUDE_SESSION_ID || 'unknown',
  cwd: process.cwd()
}) + '\n';
fs.appendFileSync(logFile, entry);
" 2>/dev/null || true

node -e "
const input = require('fs').readFileSync('/dev/stdin', 'utf8');
try {
  const data = JSON.parse(input);
  const cmd = (data.tool_input && data.tool_input.command) || '';
  const blocked = [
    'rm -rf /',
    'rm -rf ~',
    'dd if=',
    'mkfs',
    ':(){:|:&};:'
  ];
  const isBlocked = blocked.some(b => cmd.includes(b));
  if (isBlocked) {
    console.log(JSON.stringify({ decision: 'block', reason: 'Claudopus safety: destructive command blocked — ' + cmd.slice(0, 80) }));
  }
} catch(e) {}
" 2>/dev/null || true
